export const 役電符 = (bi) => {
    const u = bi.u, k = 2.55;
    const X = (c) => (c - 3.75) * k;
    const Z = (r) => (r - 5.3) * k + 1.0;
    const 線 = (書, 寬 = 0.34) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.36) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 點 = (x, z, r = 0.4) => bi.塊(p => p.M(X(x - r), Z(z)).C(X(x - r), Z(z - r * 1.3), X(x + r), Z(z - r * 1.3), X(x + r), Z(z))
        .C(X(x + r), Z(z + r * 1.3), X(x - r), Z(z + r * 1.3), X(x - r), Z(z)).close());
    // 雨冠
    線(p => p.M(X(0.2), Z(5.55)).L(X(7.1), Z(5.48)), 0.84);
    出(p => p.M(X(0.45), Z(5.60)).L(X(0.43), Z(20.49)).C(X(0.42), Z(21.14), X(0.32), Z(21.62), X(0.17), Z(21.95)), 0.76);
    出(p => p.M(X(6.5), Z(5.60)).L(X(6.48), Z(25.35)).C(X(6.45), Z(26.32), X(6.2), Z(26.97), X(5.9), Z(27.21)), 0.76);
    線(p => p.M(X(1.0), Z(6.30)).L(X(2.7), Z(6.26)), 0.57);
    線(p => p.M(X(1.0), Z(6.90)).L(X(2.7), Z(6.86)), 0.57);
    線(p => p.M(X(1.0), Z(7.50)).L(X(2.7), Z(7.46)), 0.57);
    線(p => p.M(X(4.0), Z(6.30)).C(X(4.80), Z(6.12), X(5.30), Z(6.20), X(5.6), Z(6.35)), 0.57);
    線(p => p.M(X(4.0), Z(6.90)).C(X(4.80), Z(6.72), X(5.30), Z(6.80), X(5.6), Z(6.95)), 0.57);
    線(p => p.M(X(4.0), Z(7.50)).C(X(4.80), Z(7.32), X(5.30), Z(7.40), X(5.6), Z(7.55)), 0.57);
    線(p => p.M(X(3.4), Z(5.65)).L(X(3.38), Z(8.30)), 0.72);
    // 電曲三疊承長 S 垂
    線(p => p.M(X(3.35), Z(8.40)).C(X(1.9), Z(8.82), X(1.8), Z(10.12), X(3.0), Z(10.28)).C(X(4.2), Z(10.44), X(4.3), Z(11.58), X(3.1), Z(11.90)).C(X(2.0), Z(12.39), X(2.1), Z(13.68), X(3.2), Z(13.85)).C(X(4.4), Z(14.01), X(4.4), Z(15.30), X(3.2), Z(15.63)), 0.68);
    出(p => p.M(X(3.2), Z(15.79)).C(X(2.5), Z(17.09), X(3.7), Z(18.38), X(3.1), Z(19.84)).C(X(2.6), Z(20.97), X(3.4), Z(22.11), X(3.25), Z(22.84)), 0.68);
    點(3.45, 23.81, 0.42);
};
